import{_ as s,C as e,o as g,c as d,a3 as l,E as n,w as p,j as t,a}from"./chunks/framework.CH_GxKL1.js";const f=JSON.parse('{"title":"","description":"","frontmatter":{"prev":{"text":"ch02 - 认识你的杏仁核","link":"/readings/Taming_Your_Amygdala/contexts/Chapter 02 - 认识你的杏仁核"},"next":{"text":"Taming Your Amygdala","link":"/readings/Taming_Your_Amygdala/"}},"headers":[],"relativePath":"readings/Taming_Your_Amygdala/contexts/Chapter 03 - 目标设定：夺回生活的第一步.md","filePath":"readings/Taming_Your_Amygdala/contexts/Chapter 03 - 目标设定：夺回生活的第一步.md","lastUpdated":1781773461000}'),_={name:"readings/Taming_Your_Amygdala/contexts/Chapter 03 - 目标设定：夺回生活的第一步.md"};function i(h,r,u,m,c,x){const o=e("SplitNoteInsert");return g(),d("div",null,[r[3]||(r[3]=l('<h2 id="title" tabindex="-1">第三章 -- 目标设定：夺回生活的第一步 <a class="header-anchor" href="#title" aria-label="Permalink to &quot;第三章 -- 目标设定：夺回生活的第一步 {#title}&quot;">​</a></h2><p>你可能还记得，完全摆脱焦虑是不可能的。 相反，我们的目标是管理它。 要做到这一点，你必须明确你的人生目标，并获得必要的工具，以确保焦虑和担忧不会阻碍你实现这些目标。 在本章中，你将探索焦虑、紧张、担忧、畏惧、谨慎、恐惧或恐慌感是如何干扰你的人生的，你将有机会选择你希望尽管焦虑仍然要达成的目标。 你不必放弃你的目标，任由杏仁核主宰你的生活。</p><p>一个很好的起点是审视你的日常生活。 当你每天起床时，你是否有关于自己想做什么的具体想法，还是直接投入当天的活动？ 也许你有一个每天应该做什么的清单，实际上要求相当高。 无论你如何开始你的一天，你对自己将要做的事情都有一定的期望，我们将其称为你的目标。 有时，这些日常目标会被焦虑、担忧或恐慌所阻碍。</p><h3 id="h3-1" tabindex="-1">焦虑对你日常生活的影响 <a class="header-anchor" href="#h3-1" aria-label="Permalink to &quot;焦虑对你日常生活的影响 {#h3-1}&quot;">​</a></h3><p>在本章中，你会发现一些引导思考的问题，帮助你反思焦虑如何干扰了你的生活。 你可以在这些页面上写下你的答案，或者如果需要更多空间，也可以使用额外的纸张或日记本。 对于每个提示，你可能会有不止一个想法。</p><p><strong>如果不是因为我的焦虑，我想要……</strong></p><p><strong>我的焦虑和担忧阻止了我……</strong></p><p><strong>由于我的焦虑或担忧，我不去……</strong></p><p><strong>当我感到焦虑时，我停止尝试……</strong></p><p>对你来说，考虑你想要完成的日常目标可能很困难，因为仅仅是想到做某些活动或身处某些情境，你就感到焦虑。 你甚至可能发现自己回避考虑这些场景。 这是杏仁核最限制人的方面之一：它让你停止思考潜在的目标，因为杏仁核甚至在你对某些活动产生想法时就会制造焦虑。 这种焦虑反应常常在创伤事件后出现。 例如，你可能曾经喜欢在本地商店购物，但在经历一次车祸后，你现在发现自己因为与驾驶相关的焦虑而很难开车去任何地方。 结果，你甚至可能不再考虑购物，因为那需要你开车。</p><p>为了解决这个困境并精确找出你的目标，考虑一下你过去在日常生活中常做什么，这样你就能识别出焦虑、畏惧、担忧或恐慌正在阻碍你去考虑什么。</p><p><strong>在我出现这些焦虑问题之前，我曾经……</strong></p><p><strong>在这一切之前，我记得我曾经真的很享受……</strong></p><p><strong>我的朋友们奇怪为什么我不再……</strong></p><p><strong>我真的很怀念能够……</strong></p><p><strong>由于焦虑，我的生活发生的一种变化是我不再……</strong></p><p>现在回顾你所写的内容，开始确定一些你希望努力实现的人生目标。</p><p><strong>我想要努力实现的一些人生目标是……</strong></p><h3 id="h3-2" tabindex="-1">焦虑对你人际关系的影响 <a class="header-anchor" href="#h3-2" aria-label="Permalink to &quot;焦虑对你人际关系的影响 {#h3-2}&quot;">​</a></h3><p>另一种识别焦虑如何限制你的方法是考虑你与家人、朋友和同事的关系。 你希望能与生活中的人一起做些什么，但焦虑阻止了你？ 你在错过哪些类型的乐趣？ 你曾经有过哪些互动而现在却在回避？ 在考虑这些问题时，你可能会发现焦虑正在以令人惊讶的方式影响你的人际关系。</p><p>例如，在经历了一段动荡且充满争吵的恋爱关系后，布列塔尼发现自己不再享受与同事辩论或在与姐姐的争执中为自己辩护。 她现在在遇到一点点冲突的苗头时就感到焦虑，并持续担心冒犯或激怒他人。 同样，考虑一下乔的情况，他拒绝了一个与一群朋友一起聚会的邀请，因为他在非结构化的群体互动中会感到焦虑。 乔错失了结交新朋友和与为数不多的几位朋友共度时光的机会。</p><p>考虑一下你与同事、家人和朋友的关系和互动是如何受焦虑影响的。 请记住，对于每个提示，你可以写多个答案，尤其是在不同的人面前或不同的情境下你的反应不同时。</p><p><strong>虽然曾经不困扰我，但我发现自己在人们……时会感到焦虑</strong></p><p><strong>我希望我能和别人一起做……</strong></p><p><strong>焦虑干扰了我的人际关系，因为我不……</strong></p><p><strong>当我的家人或朋友邀请我时，我希望我能……</strong></p><p><strong>我常常想开口说些什么，但在……面前却没有说</strong></p><p><strong>如果不是因为我的焦虑，别人会看到我做或成为……</strong></p><p><strong>我本可以和_____________一起玩得更开心，通过做或去……</strong></p><p><strong>我想要能够对_______________说或解释……</strong></p><p><strong>在我的恋爱关系中，我想要……</strong></p><p><strong>我与_______________的关系会更好，如果我能……</strong></p><p><strong>我的焦虑阻止我去或参加……</strong></p><p><strong>在我的人际关系中，我需要更多……</strong></p><p>现在回顾你所写的内容，确定一些你在人际关系方面希望达成、但焦虑正在阻碍的目标。</p><p><strong>在工作中，与同事相处，我希望能够……</strong></p><p><strong>与我的伴侣，我希望能够……</strong></p><p><strong>与我的家人，我希望能够……</strong></p><p><strong>与我的朋友，我希望能够……</strong></p><p><strong>在娱乐和乐趣方面，我希望能够……</strong></p><h3 id="焦虑对你工作或职业的影响" tabindex="-1">焦虑对你工作或职业的影响 <a class="header-anchor" href="#焦虑对你工作或职业的影响" aria-label="Permalink to &quot;焦虑对你工作或职业的影响&quot;">​</a></h3><p>除了人际关系之外，焦虑可能以多种方式影响你的工作或职业。 例如，我最早的一位来访者想获得护理学位，但她不断从一门必修课中退学，因为这门课需要做几次演讲，而她害怕公开演讲。 这种焦虑甚至阻止了她开始她所渴望的职业生涯。 焦虑和担忧也可能阻碍某人在已有职业中晋升。 他们可能因焦虑而表现出糟糕的工作表现，或难以按时完成任务。</p><p>试着找出焦虑阻止你在工作中取得更大成功的一些具体方式。</p><p><strong>如果不是因为我在工作中的焦虑，我会……</strong></p><p><strong>如果我能……，这将改善我的工作表现</strong></p><p><strong>焦虑阻止了我晋升，因为我似乎无法……</strong></p><p><strong>焦虑通过……损害了我的时间管理</strong></p><p><strong>我的晋升受到限制，因为我拒绝了……的机会</strong></p><p>现在回顾你所写的内容，看看焦虑在哪些方面造成了干扰，并确定你在工作方面为自己设定的目标。</p><p><strong>在工作中，我希望能够……</strong></p><h3 id="从杏仁核手中夺回对生活的掌控" tabindex="-1">从杏仁核手中夺回对生活的掌控 <a class="header-anchor" href="#从杏仁核手中夺回对生活的掌控" aria-label="Permalink to &quot;从杏仁核手中夺回对生活的掌控&quot;">​</a></h3><p>在完成本章的提示之后，你可以更清楚地认识到焦虑如何对生活的特定方面产生负面影响。 重要的是要记住，杏仁核是在生活在非常不同环境中的原始人类身上发展出来的，它的反应并不总是适合你今天所过的生活。 这就是为什么你需要确保是你自己的目标在主导你的生活，而不是杏仁核产生的防御过程。 现在正是诚实地审视那些由于杏仁核产生的焦虑而无法追求或实现的任何目标的时候。 专注于具体的目标，是开始探索如何从焦虑的限制性影响中夺回你生活的好方法。</p><h3 id="练习表-重要目标" tabindex="-1">练习表:重要目标 <a class="header-anchor" href="#练习表-重要目标" aria-label="Permalink to &quot;练习表:重要目标&quot;">​</a></h3><p>本练习表将帮助你为自己选择一些目标，然后从两个不同维度——<strong>重要性</strong>和<strong>焦虑程度</strong>——对这些目标进行评分，以确定你应该集中精力关注哪些目标。</p><p>首先，回顾你在本章之前提示中所写的目标——你在日常生活、人际关系和工作或职业中想要完成的事情。 表述目标的一个好方法是以&quot;我想要……&quot;或&quot;我希望能够……&quot;这样的短语开头。 如果你发现自己写下了相当多的目标并感到不堪重负，请知道，你只是把它们写下来——你不是在承诺要完成所有这些目标，只是在考虑各种可能性。</p><p>接下来，使用 1 到 10 的评分标准对每个目标的<strong>重要性</strong>进行评分，对更有意义或对你更有益的目标给予更高的分数。 例如，乔舒亚可能有一个目标是能更自在地与狗相处，另一个目标是在高速公路上驾车时更平静、更自信。 他把与狗舒适相处的重要性评为 5 分，因为这个目标的目的是偶尔去拜访一位养了一只西伯利亚哈士奇的朋友家。 然而，他将关于在高速公路上驾车的目标评为 9 分，因为对他来说更重要的是不再每天浪费时间在绕道上通勤上班。 请务必使用你自己的视角来判断什么重要；虽然你可能会考虑别人希望你做什么，但最终你应该决定哪些目标对你自己最有意义。</p><p>然后使用 1 到 10 的评分标准对每个目标相关的<strong>预期焦虑水平</strong>进行评分，分数越高表示焦虑水平越高。 如果你发现某个目标的焦虑评分因情境而异而难以判断，你可能想把它写成两个独立的目标。 例如，乔舒亚上下午班，他在中午高峰期开车上班时感到非常焦虑——绝对是 9 分或 10 分。 但当他深夜交通较稀少回家时，只有 6 分。 乔舒亚可以写一个关于开车上班的目标，另一个关于开车回家的目标。</p><p>目标实现通常最好以渐进或分步骤的过程来完成，因此每当你觉得一个目标根据情境不同可能有不同的焦虑水平时，将其拆分为独立的目标是有帮助的。</p><table tabindex="0"><thead><tr><th>目标（我想要……或我希望能够……）</th><th>重要性（1–10）</th><th>焦虑程度（1–10）</th></tr></thead><tbody><tr><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td></tr><tr><td></td><td></td><td></td></tr></tbody></table><p><em>Copyright © 2022 Catherine M. Pittman. Taming Your Amygdala. All rights reserved.</em></p><p>以这种方式列出你的目标并进行评分是一项重要成就。 你可能注意到，仅仅是思考你的目标就会让你感到一些焦虑，所以当你克服焦虑来考虑这些目标时，请给自己赞赏！ 你正在迈出第一步，走向一个专注于你自己的抱负、不受杏仁核支配的生活。 你没有让焦虑阻碍你。</p><p>现在，你已经准备好选择你想首先着手处理的目标了。 在回顾上一张练习表中的每个目标时，考虑你与之相关的焦虑水平。 导致较少焦虑的目标更容易实现。 事实上，当人们开始写下他们的目标时，有时会意识到他们对某个目标的焦虑足够低，可以立即开始着手处理。 例如，维多利亚正从一次险些溺水的经历中恢复，当她写下自己去湖边这个目标时，她意识到实际上是去湖里游泳这个目标让她焦虑。 她将去湖边的焦虑评为 2 分，然后另外增加了一个关于游泳的目标，评为 10 分。 这个认识激励维多利亚制定了一个去湖边的计划，这是她在开始写下目标并评分之前从未考虑过可能的事情。</p><p>正如有些目标因为引起的焦虑较少而更容易实现一样，其他目标因为需要你经历更多焦虑而具有挑战性。 焦虑从来不令人愉快，推动自己完成这个过程的唯一理由是达成真正对你重要的事情。 因此，我只要求我的来访者在目标涉及对他们重要的事情时才让自己经历焦虑。 例如，安吉洛害怕开车、乘坐公共汽车、坐火车或乘飞机，但对他来说唯一重要的情况是开车。 他没有理由坐公共汽车或火车，也很少有机会乘飞机。 不能开车正在限制他的生活，所以这是要重点关注的目标。</p><p>请记住，从你的生活中消除所有焦虑是不必要、不健康也不可能的。 相反，驯服杏仁核的目的是让你掌控你的生活，而你选择的目标将引导这个过程。 这并不是说一旦你理解了如何克服焦虑的限制或者你有了新的志向，就不能增加新的目标。 例如，安娜尼亚对克服对狗的恐惧没有兴趣，直到她开始与养了一只拉布拉多寻回犬的瑞安约会。 有时你的生活发生变化，导致你重新评估某个目标的重要性。</p><p>回顾你的目标列表，根据哪些目标对你最重要以及哪些目标最容易实现，决定从哪里开始。 我建议开始时选择不超过三到四个目标。 现在你已经准备好学习如何实现这些目标。 在阅读时牢记你的目标。 我们将在第9章回到你特定的目标列表。 与此同时，接下来的两章将帮助你理解杏仁核在大脑中制造焦虑的方式，因为了解这些知识对于学习有效策略来实现你的目标至关重要。</p>',65)),n(o,{target:"title",until:"h3-1"},{default:p(()=>[...r[0]||(r[0]=[t("p",null,'第一步，观察和内省。 用更全面的视角看一下"焦虑"和"恐惧"是如何影响到我们的 --- 思维、情绪和生理反应。',-1)])]),_:1}),n(o,{target:"h3-1",scope:"section"},{default:p(()=>[...r[1]||(r[1]=[t("ol",null,[t("li",null,"焦虑压制了“可能性”。")],-1),t("blockquote",null,[t("p",null,"它让你停止思考潜在的目标，因为杏仁核甚至在你对某些活动产生想法时就会制造焦虑。")],-1),t("ol",{start:"2"},[t("li",null,[a("正如很多心理治疗的第一课，我们需要做的永远是： "),t("strong",null,"找到 trigger"),a(" , 然后在意识层面建立 “trigger -- result” 的明确相关性。")]),t("li",null,"去做一下本节练习。")],-1)])]),_:1}),n(o,{target:"h3-2",scope:"section"},{default:p(()=>[...r[2]||(r[2]=[t("ul",null,[t("li",null,"我对人际交往焦虑吗？对哪种类型、哪种场景、哪些方式的交往焦虑？"),t("li",null,"去做一下本节练习。")],-1)])]),_:1})])}const q=s(_,[["render",i]]);export{f as __pageData,q as default};
